#include <iostream>
using namespace std;

class Point {
public:
  int x, y;
  Point(int x, int y) : x(x), y(y) {
    cout << "Point created" << endl;
  }
  ~Point() {
    cout << "Point destroyed" << endl;
  }
};

int main() {
  Point* p = new Point(3, 4);
  cout << "(" << p->x << ", " << p->y << ")" << endl;
  delete p;
  return 0;
}
